16	    orderId: "ord-ent-1", accountId: "acct-ent-1", status: "pending", totalCents: 75000, currency: "USD", createdAt: new Date(),
17	    lineItems: [{ productName: "Enterprise License", quantity: 1, unitPriceCents: 75000 }]
18	  });
19	
20	  // Create an invoice
21	  await db.collection("invoices").insertOne({
22	    invoiceId: "inv-ent-1", orderId: "ord-ent-1", accountId: "acct-ent-1", invoiceNumber: "INV-001", amountCents: 75000, totalCents: 75000, status: "sent", currency: "USD", issuedAt: new Date(), dueAt: new Date(),
23	  });
24	
