29	  strictEqual(summary.accountName, "Enterprise Corp", "regression: account name in summary");
30	  strictEqual(summary.invoiceStatus, "sent", "regression: invoice status in summary");
31	
32	  // === NEW: preferredPaymentMethod field ===
33	  const updated = await updateAccount(db, "acct-ent-1", { preferredPaymentMethod: "wire_transfer" });
34	  strictEqual(updated.preferredPaymentMethod, "wire_transfer", "new: account has preferredPaymentMethod");
35	
36	  // Verify in live DB
37	  const liveAcct = await db.collection("accounts").findOne({ accountId: "acct-ent-1" });
38	  strictEqual(liveAcct.preferredPaymentMethod, "wire_transfer", "new: live DB has preferredPaymentMethod");
39	
